script:
const loader = root_element.querySelector('.loader');
const tableContainer = root_element.querySelector('.table-container');
const monthFilter = root_element.querySelector('.month-filter');

const thStyle = "padding:8px 12px; text-align:left; border-bottom:1px solid #ddd; font-weight:600;";
const tdStyle = "padding:8px 12px; border-bottom:1px solid #eee; vertical-align:middle;";

function getInitialsAvatar(name) {
    const initial = (name || "?").charAt(0).toUpperCase();
    const colors = ["#e74c3c","#3498db","#2ecc71","#f39c12","#9b59b6","#1abc9c","#e67e22","#e91e63"];
    const colorIndex = (name || "").charCodeAt(0) % colors.length;
    const bg = colors[colorIndex];
    return `<div style="width:70px;height:70px;background:${bg};border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:700;color:#fff;font-family:sans-serif;">${initial}</div>`;
}

// ✅ Date Range widget ke saved filters se company + from/to nikaalo
function drGetGlobalFilters() {
    return {
        from: sessionStorage.getItem('dr_from') || '',
        to: sessionStorage.getItem('dr_to') || '',
        company: sessionStorage.getItem('dr_company') || frappe.defaults.get_default("company") || ''
    };
}

function loadData(month) {
    loader.style.display = "block";
    tableContainer.innerHTML = "";

    let g = drGetGlobalFilters();

    frappe.call({
        method: "frappe.desk.query_report.run",
        args: {
            report_name: "Sales vs Stock",
            filters: {
                month: month || "",
                from_date: g.from,
                to_date: g.to,
                company: g.company
            }
        },
        callback: function(r) {
            loader.style.display = "none";

            if (!r.message || !r.message.result || r.message.result.length === 0) {
                tableContainer.innerHTML = "<p>No data found.</p>";
                return;
            }

            const rows = r.message.result;

            let html = `
                <table style="width:100%; border-collapse:collapse;">
                    <thead>
                        <tr style="background:#f5f5f5;">
                            <th style="${thStyle}">Image</th>
                            <th style="${thStyle}">Item</th>
                            <th style="${thStyle}">Month</th>
                            <th style="${thStyle}">Sales Qty</th>
                            <th style="${thStyle}">Stock Qty</th>
                            <th style="${thStyle}">Status</th>
                        </tr>
                    </thead>
                    <tbody>
            `;

            rows.forEach(function(row) {
                const itemName = row.item_name || row.item_code || row.item || "";
                const avatar = getInitialsAvatar(itemName);

                const imgHtml = (row.image_url && row.image_url.trim() !== "")
                    ? `<div class="img-wrapper" data-avatar="${encodeURIComponent(avatar)}">
                           <img
                            src="${row.image_url}"
                            style="width:70px;height:70px;object-fit:cover;border-radius:6px;"
                            onerror="var w=this.parentElement; w.innerHTML=decodeURIComponent(w.getAttribute('data-avatar'));" />
                       </div>`
                    : avatar;

                const statusColor = row.status === "Low Stock" ? "#e74c3c" : "#27ae60";
                const statusHtml = `<span style="background:${statusColor}20;color:${statusColor};
                    padding:3px 10px;border-radius:12px;font-size:12px;font-weight:600;">
                    ${row.status}
                </span>`;

                html += `
                    <tr>
                        <td style="${tdStyle}">${imgHtml}</td>
                        <td style="${tdStyle}">${itemName}</td>
                        <td style="${tdStyle}">${row.month || ""}</td>
                        <td style="${tdStyle}">${row.sales_qty || 0}</td>
                        <td style="${tdStyle}">${row.stock_qty || 0}</td>
                        <td style="${tdStyle}">${statusHtml}</td>
                    </tr>
                `;
            });

            html += `</tbody></table>`;
            tableContainer.innerHTML = html;
        }
    });
}

// ✅ Initial load: pehle try karo current global date-range se month nikaalna
const g0 = drGetGlobalFilters();
const currentMonth = g0.to ? (new Date(g0.to).getMonth() + 1) : (new Date().getMonth() + 1);
monthFilter.value = currentMonth;
loadData(currentMonth);

monthFilter.addEventListener("change", function() {
    loadData(this.value);
});

// ✅ IMPORTANT: Date Range widget ka Apply -> ye event fire hota hai globally.
// Us waqt month-dropdown ko bhi naye range ke hisaab se update karke reload karo.
document.addEventListener('dashboardFilterChanged', function(e) {
    let g = drGetGlobalFilters();
    let newMonth = g.to ? (new Date(g.to).getMonth() + 1) : monthFilter.value;
    monthFilter.value = newMonth;
    loadData(newMonth);
});

