script:
function drGetFilters() {
    // ✅ Date Range widget jo filter save karta hai (sessionStorage) wahi use karo,
    // agar kuch saved nahi hai to fallback me last-1-month
    let from = sessionStorage.getItem('dr_from');
    let to = sessionStorage.getItem('dr_to');
    let company = sessionStorage.getItem('dr_company') || frappe.defaults.get_default("company");

    if (!from || !to) {
        from = frappe.datetime.add_months(frappe.datetime.get_today(), -1);
        to = frappe.datetime.get_today();
    }
    return { from_date: from, to_date: to, company: company };
}

function renderTSIList(container, data, sortDir) {
    if (!container) return;
    container.innerHTML = "";

    if (!data.length) {
        container.innerHTML = "<p>No data available</p>";
        return;
    }

    data.sort((a, b) => {
        let qtyA = a.qty || a.stock_qty || a.total_qty || Object.values(a)[1] || 0;
        let qtyB = b.qty || b.stock_qty || b.total_qty || Object.values(b)[1] || 0;
        return sortDir === "desc" ? qtyB - qtyA : qtyA - qtyB;
    });

    data.slice(0, 5).forEach((row, index) => {
        let item = row.item_name || row.item_code || row.item || Object.values(row)[0];
        let qty = row.qty || row.stock_qty || row.total_qty || Object.values(row)[1] || 0;

        container.insertAdjacentHTML("beforeend", `
            <div class="tsi-row">
                <div class="tsi-rank">${index + 1}.</div>
                <div class="tsi-item">${item}</div>
                <div class="tsi-qty">${qty}</div>
            </div>
        `);
    });
}

function loadTopSellingItems() {
    let f = drGetFilters();
    frappe.call({
        method: "frappe.desk.query_report.run",
        args: {
            report_name: "Top Selling Items 1",
            filters: { from_date: f.from_date, to_date: f.to_date, company: f.company }
        },
        callback: function (r) {
            renderTSIList(root_element.querySelector("#top-selling-items"), r.message.result || [], "desc");
        }
    });
}

function loadLeastSellingItems() {
    let f = drGetFilters();
    frappe.call({
        method: "frappe.desk.query_report.run",
        args: {
            report_name: "Least Selling Items",
            filters: { from_date: f.from_date, to_date: f.to_date, company: f.company }
        },
        callback: function (r) {
            renderTSIList(root_element.querySelector("#least-selling-items"), r.message.result || [], "asc");
        }
    });
}

function loadTSIBlocks() {
    loadTopSellingItems();
    loadLeastSellingItems();
}

// ✅ Initial load — thoda wait taaki root_element/DOM ready ho
setTimeout(loadTSIBlocks, 500);

// ✅ IMPORTANT: Date Range widget jab bhi Apply hota hai, ye event fire hota hai
// (dr-widget.js: document.dispatchEvent(new CustomEvent('dashboardFilterChanged', ...)))
document.addEventListener('dashboardFilterChanged', function () {
    loadTSIBlocks();
});

