script:
// ✅ Frappe shorten_number null crash fix
(function patchFrappe() {
  function applyPatch() {
    if (frappe && frappe.utils && frappe.utils.shorten_number) {
      var _orig = frappe.utils.shorten_number;
      frappe.utils.shorten_number = function(number) {
        if (number === null || number === undefined) return '0';
        return _orig.apply(this, arguments);
      };
    }
  }
  if (typeof frappe !== 'undefined') {
    applyPatch();
  } else {
    setTimeout(applyPatch, 1000);
  }
})();

var sel = function(id) {
    var el = document.getElementById(id);
    if (el) {
        return el;
    }
    if (typeof root_element !== "undefined" && root_element) {
        return root_element.querySelector("#" + id);
    }
    return null;
};

var drState = {
  preset     : 'thismonth',
  from       : '',
  to         : '',
  view       : 'qty',
  company    : '',
  dropOpen   : false,
  customOpen : false,
  busy       : false   // ✅ overlapping-call lock
};

var PRESET_IDS = ['last3', 'last7', 'thismonth', 'prevmonth', 'finyr', 'custom'];

function fmt(d) {
  return d.toLocaleDateString('en-IN', {
    day: 'numeric', month: 'short', year: 'numeric'
  });
}

function isoDate(d) {
  return d.getFullYear() + '-' +
         String(d.getMonth() + 1).padStart(2, '0') + '-' +
         String(d.getDate()).padStart(2, '0');
}

function getPresetDates(p) {
  var now = new Date();
  var y = now.getFullYear(), m = now.getMonth();
  if (p === 'last3')     { var f = new Date(now); f.setDate(f.getDate() - 3);  return [f, new Date(now)]; }
  if (p === 'last7')     { var f = new Date(now); f.setDate(f.getDate() - 7);  return [f, new Date(now)]; }
  if (p === 'thismonth') { return [new Date(y, m, 1),     new Date(y, m + 1, 0)]; }
  if (p === 'prevmonth') { return [new Date(y, m - 1, 1), new Date(y, m, 0)];  }
  if (p === 'finyr')     { var fy = m >= 3 ? y : y - 1; return [new Date(fy, 3, 1), new Date(fy + 1, 2, 31)]; }
  return null;
}

(function injectStyle() {
  var styleId = 'dr-silent-style';
  if (!document.getElementById(styleId)) {
    var style = document.createElement('style');
    style.id = styleId;
    style.textContent = [
      '.dr-offscreen { position: fixed !important; top: -9999px !important; left: -9999px !important; opacity: 0 !important; pointer-events: none !important; }',
      /* ✅ Funnel/filter icon ko turant, bina kisi flash/delay ke hide karta
         hai — pure CSS se, page render hote hi apply ho jaata hai, JS ke
         chalne ka wait nahi karna padta. Chrome ka :has() selector SVG
         "filter" icon wale button ko directly target karta hai. */
      '.dashboard-widget-box button:has(svg use[href*="filter" i]) { display: none !important; }',
      '.dashboard-widget-box a:has(svg use[href*="filter" i]) { display: none !important; }',
      '.dashboard-widget-box .btn:has(svg use[href*="filter" i]) { display: none !important; }'
    ].join(' ');
    document.head.appendChild(style);
  }
})();

function openDropdown() {
  drState.dropOpen = true;
  sel('dr-dropdown').classList.add('open');
  sel('dr-chevron').classList.add('open');
}

function closeDropdown() {
  drState.dropOpen   = false;
  drState.customOpen = false;
  sel('dr-dropdown').classList.remove('open');
  sel('dr-chevron').classList.remove('open');
  sel('dr-custom-box').classList.remove('open');
}

function toggleDropdown() {
  drState.dropOpen ? closeDropdown() : openDropdown();
}

function setActiveOption(p) {
  PRESET_IDS.forEach(function(id) {
    var el = sel('dr-opt-' + id);
    if (el) el.classList.remove('dr-active');
  });
  var active = sel('dr-opt-' + p);
  if (active) active.classList.add('dr-active');
}

function selectPreset(p) {
  drState.preset = p;
  setActiveOption(p);
  if (p === 'custom') {
    drState.customOpen = !drState.customOpen;
    sel('dr-custom-box').classList.toggle('open', drState.customOpen);
    sel('dr-btn-label').textContent = 'Custom Range';
  } else {
    drState.customOpen = false;
    sel('dr-custom-box').classList.remove('open');
    var dates = getPresetDates(p);
    drState.from = isoDate(dates[0]);
    drState.to   = isoDate(dates[1]);
    sel('dr-btn-label').textContent = fmt(dates[0]) + ' \u2013 ' + fmt(dates[1]);
  }
}

// ✅ disable/enable all interactive controls while a chart-refresh chain is running
function setControlsDisabled(state) {
  var ids = ['dr-apply-btn', 'dr-btn-qty', 'dr-btn-amt', 'dr-company-select', 'dr-main-btn'];
  ids.forEach(function(id) {
    var el = sel(id);
    if (el) el.disabled = state;
  });
}

/* ────────────────────────────────────────────────────────────────
   ✅ Chart card ko humara apna API se turant, non-blocking render karta hai
   ✅ ALONG WITH ISKE — Dashboard Chart ke filters_json ko bhi sahi
      (flat key:value) format mein update karta hai, taaki jab user
      funnel icon / "..." → "View Report" se underlying report page
      khole, to wahan bhi currently-selected date range hi dikhe
      (stale/purana filter na dikhe).
   - filters_json ka format Report-type Dashboard Charts ke liye
     Frappe khud isi flat-object format mein expect karta hai, isliye
     ye funnel-icon dialog ko todhta nahi hai.
   ──────────────────────────────────────────────────────────────── */

// Har report ke apne actual filter fieldnames — bilkul unke .js files
// mein diye gaye fieldname ke jaise hi (view_type vs metric, etc.)
var CHART_FILTER_MAP = {
  "Sales Trend": {
    from_date: "from", to_date: "to", view_type: "view", company: "company"
  },
  "Sales Progress": {
    from_date: "from", to_date: "to", view_type: "view", company: "company"
  },
  "Top Selling Items Chart": {
    from_date: "from", to_date: "to", metric: "view", company: "company"
  },
  "Least Selling Items Chart": {
    from_date: "from", to_date: "to", metric: "view", company: "company"
  },
  "Sales vs Stock": {
    from_date: "from", to_date: "to", metric: "view", company: "company"
  }
};

// ✅ IMPORTANT: Dashboard-widget ka TITLE aur uski underlying REPORT ka
// naam alag-alag ho sakte hain (jaisa "Top Selling Items Chart" error
// se confirm hua — widget-title se navigate karne par report exist hi
// nahi karta). Isliye widget-title se actual report-name tak ek
// explicit mapping banate hain — jahan naam same hai wahan bhi likh
// diya hai (safety ke liye), taaki koi confusion na ho.
var REPORT_NAME_MAP = {
  "Sales Trend": "Sales Trend",
  "Sales Progress": "Sales Progress",
  "Top Selling Items Chart": "Top Selling Items 1",
  "Least Selling Items Chart": "Least Selling Items",
  "Sales vs Stock": "Sales vs Stock"
};

function buildReportFilters(chartName, payload) {
  var map = CHART_FILTER_MAP[chartName] || {};
  var out = {};
  Object.keys(map).forEach(function(reportField) {
    var payloadKey = map[reportField];
    out[reportField] = payload[payloadKey];
  });
  return out;
}

var _applyDashboardFiltersCallCount = 0;

function applyDashboardFilters(payload) {

  _applyDashboardFiltersCallCount++;
  console.log('DR DEBUG: applyDashboardFilters called. Total calls this page-load:', _applyDashboardFiltersCallCount, 'payload:', payload);

  var chartNames = Object.keys(CHART_FILTER_MAP);
  var pending = chartNames.length;
  var failed = [];

  chartNames.forEach(function(chartName) {

    // 1) Chart card ko turant render karo (fast, user ko turant dikhta hai)
    fetchAndRenderChart(chartName, payload, function(ok) {
      if (!ok) failed.push(chartName);
      pending--;
      checkDone();
    });

    // 2) Alag se, filters_json ko background mein sync karo — isse
    //    UI render block nahi hota, sirf "View Report" ke liye state
    //    theek rehti hai. Existing keys (jaise limit/period) preserve
    //    karte hain, sirf date/view/company overwrite karte hain.
    //syncChartFiltersJson(chartName, payload);
  });

  function checkDone() {
    if (pending > 0) return;

    drState.busy = false;
    setControlsDisabled(false);

    if (failed.length) {
      frappe.show_alert({ message: '⚠ Fail: ' + failed.join(', '), indicator: 'red' }, 5);
    } else {
      frappe.show_alert({ message: '✔ Charts updated', indicator: 'green' }, 2);
    }
  }
}

function syncChartFiltersJson(chartName, payload) {
  var newFilters = buildReportFilters(chartName, payload);

  frappe.db.get_value('Dashboard Chart', chartName, 'filters_json').then(function(r) {
    var existing = {};
    try {
      existing = JSON.parse((r && r.message && r.message.filters_json) || '{}');
    } catch (e) {
      existing = {};
    }

    var merged = Object.assign({}, existing, newFilters);

    frappe.call({
      method: 'frappe.client.set_value',
      args: {
        doctype  : 'Dashboard Chart',
        name     : chartName,
        fieldname: 'filters_json',
        value    : JSON.stringify(merged)
      },
      callback: function() {
        // silent — sirf state sync karna hai, UI isse block nahi hota
      },
      error: function(err) {
        console.error('syncChartFiltersJson set_value error:', chartName, err);
      }
    });
  }).catch(function(err) {
    console.error('syncChartFiltersJson get_value error:', chartName, err);
  });
}

function fetchAndRenderChart(chartName, payload, cb) {
  frappe.call({
    // ⚠️ apna actual module path yahan confirm karke daalo
    // (bench console: frappe.get_attr('franchise_erp.api.get_chart_data'))
    method: 'franchise_erp.api.get_chart_data',
    args: {
      chart_name: chartName,
      from_date : payload.from,
      to_date   : payload.to,
      view_type : payload.view,
      company   : payload.company || ''
    },
    callback: function(r) {
      if (!r.message || !r.message.chart) {
        // ✅ SAFETY-NET: agar backend se chart missing/null aaye (jaise
        // kisi report mein data na milne par None return ho jaaye), to
        // widget ko KHAALI dikhao — purana stale (galat) chart screen
        // par reh jaane se behtar hai ki blank/empty state dikhe.
        console.warn('fetchAndRenderChart: no chart data for', chartName, '— rendering empty state instead of leaving stale data');
        renderChartInWidget(chartName, {
          data: { labels: [], datasets: [{ name: chartName, values: [] }] },
          type: 'bar'
        });
        if (cb) cb(false);
        return;
      }
      renderChartInWidget(chartName, r.message.chart);
      if (cb) cb(true);
    },
    error: function(err) {
      console.error('fetchAndRenderChart error:', chartName, err);
      if (cb) cb(false);
    }
  });
}

// ✅ Har chart-card ke current frappe.Chart instance ko track karta hai,
// taaki naya chart banane se pehle purane ko properly destroy() kar sakein.
// (frappe-charts ka BaseChart apne window resize/orientationchange listener
// kabhi khud clean-up nahi karta jab tak destroy() na bulaya jaaye — isliye
// baar-baar filter apply karne par ye listeners window par accumulate ho
// rahe the, jo funnel-icon dialog khulte hi ek saath fire hoke hang kar rahe the.)
var chartInstances = {};

function renderChartInWidget(chartName, chartConfig) {
  document.querySelectorAll('.dashboard-widget-box').forEach(function(el) {
    var title = el.querySelector('.ellipsis')?.textContent?.trim();
    if (title !== chartName) return;

    var container = el.querySelector('.chart-container');
    if (!container) {
      console.error('renderChartInWidget: .chart-container not found for', chartName);
      return;
    }

    // ✅ Purana chart instance destroy karo — isse uska window
    // resize/orientationchange listener bhi clean-up ho jaata hai
    if (chartInstances[chartName] && typeof chartInstances[chartName].destroy === 'function') {
      try {
        chartInstances[chartName].destroy();
      } catch (e) {
        console.warn('chart destroy failed for', chartName, e);
      }
    }

    container.innerHTML = '';
    try {
      chartInstances[chartName] = new frappe.Chart(container, chartConfig);
    } catch (e) {
      console.error('renderChartInWidget: frappe.Chart failed for', chartName, e);
    }
  });
}

function applyFilter() {
  console.log("DEBUG 1: applyFilter called");

  if (drState.busy) {
    console.log("DEBUG 2: blocked, busy=true");
    frappe.show_alert({ message: 'Please wait, charts are still updating...', indicator: 'orange' }, 2);
    return;
  }
  console.log("DEBUG 3: not busy, proceeding");

  if (drState.preset === 'custom') {
    var f = sel('dr-from-date').value.trim();
    var t = sel('dr-to-date').value.trim();
    if (!f || !t) {
      frappe.msgprint(__('Please select both From and To dates.'));
      return;
    }
    var fd = new Date(f), td = new Date(t);
    if (td < fd) {
      frappe.msgprint(__('To date must be after From date.'));
      return;
    }
    drState.from = f;
    drState.to   = t;
    sel('dr-btn-label').textContent = fmt(fd) + ' \u2013 ' + fmt(td);
  }
  console.log("DEBUG 4: preset handling done");

  sessionStorage.setItem('dr_from',    drState.from);
  sessionStorage.setItem('dr_to',      drState.to);
  sessionStorage.setItem('dr_preset',  drState.preset);
  sessionStorage.setItem('dr_view',    drState.view);
  sessionStorage.setItem('dr_label',   sel('dr-btn-label').textContent);
  sessionStorage.setItem('dr_company', drState.company);
  console.log("DEBUG 5: sessionStorage set");

  closeDropdown();
  console.log("DEBUG 6: dropdown closed");

  var payload = {
    from   : drState.from,
    to     : drState.to,
    view   : drState.view,
    company: drState.company
  };
  console.log("DEBUG 7: payload built", payload);

  frappe.dashboardFilter = payload;
  document.dispatchEvent(new CustomEvent('dashboardFilterChanged', { detail: payload }));
  console.log("DEBUG 8: custom event dispatched");

  drState.busy = true;
  setControlsDisabled(true);
  console.log("DEBUG 9: controls disabled, calling applyDashboardFilters");

  applyDashboardFilters(payload);
  console.log("DEBUG 10: applyDashboardFilters call returned (async work in progress)");
}

function cancelDropdown() {
  closeDropdown();
}

function setView(v) {
  drState.view = v;
  sel('dr-btn-qty').classList.toggle('dr-toggle-active', v === 'qty');
  sel('dr-btn-amt').classList.toggle('dr-toggle-active', v === 'amt');
  applyFilter();
}

function loadCompanies() {
  var select = sel('dr-company-select');
  select.innerHTML = '<option value="">-- Loading... --</option>';

  var savedCompany = sessionStorage.getItem('dr_company');
  var userCompany  = frappe.defaults.get_user_default('company') ||
                     frappe.defaults.get_default('company') || '';

  var isAdmin = frappe.session.user === 'Administrator';
  var isTZU   = userCompany === 'TZU Lifestyle Private Limited';

  if (isAdmin || isTZU) {
    loadAllCompanies(select, savedCompany || userCompany);
  } else {
    loadUserCompany(select, userCompany);
  }
}

function loadAllCompanies(select, companyToSelect) {
  frappe.call({
    method: 'frappe.client.get_list',
    args: {
      doctype          : 'Company',
      fields           : ['name'],
      limit_page_length: 500,
      order_by         : 'name asc'
    },
    callback: function(r) {
      select.innerHTML     = '<option value="">-- All Companies --</option>';
      select.disabled      = false;
      select.style.opacity = '1';
      select.style.cursor  = 'pointer';

      if (r && r.message && r.message.length > 0) {
        r.message.forEach(function(row) {
          var opt = document.createElement('option');
          opt.value       = row.name;
          opt.textContent = row.name;
          select.appendChild(opt);
        });
        if (companyToSelect) {
          select.value    = companyToSelect;
          drState.company = companyToSelect;
        }
      }
    }
  });
}

function loadUserCompany(select, company) {
  select.innerHTML = '';
  var opt = document.createElement('option');
  opt.value       = company;
  opt.textContent = company || '-- No Company --';
  select.appendChild(opt);
  select.disabled      = true;
  select.style.opacity = '0.7';
  select.style.cursor  = 'not-allowed';
  drState.company = company;
}

