(function init() {
  var savedFrom    = sessionStorage.getItem('dr_from');
  var savedTo      = sessionStorage.getItem('dr_to');
  var savedPreset  = sessionStorage.getItem('dr_preset');
  var savedView    = sessionStorage.getItem('dr_view');
  var savedLabel   = sessionStorage.getItem('dr_label');
  var savedCompany = sessionStorage.getItem('dr_company');

  if (savedFrom && savedTo) {
    drState.from    = savedFrom;
    drState.to      = savedTo;
    drState.preset  = savedPreset  || 'thismonth';
    drState.view    = savedView    || 'qty';
    drState.company = savedCompany || '';
    sel('dr-btn-label').textContent = savedLabel || (savedFrom + ' \u2013 ' + savedTo);
    setActiveOption(drState.preset);
    sel('dr-btn-qty').classList.toggle('dr-toggle-active', drState.view === 'qty');
    sel('dr-btn-amt').classList.toggle('dr-toggle-active', drState.view === 'amt');
  } else {
    var dates = getPresetDates('thismonth');
    drState.from = isoDate(dates[0]);
    drState.to   = isoDate(dates[1]);
    sel('dr-btn-label').textContent = fmt(dates[0]) + ' \u2013 ' + fmt(dates[1]);
    setActiveOption('thismonth');
    sel('dr-btn-qty').classList.add('dr-toggle-active');
  }

  if (frappe.ready) {
    frappe.ready(function() { loadCompanies(); });
  } else {
    setTimeout(loadCompanies, 800);
  }

  // ✅ IMPORTANT FIX: Page load/refresh par native widgets apne default
  // (current server month) data se render ho jaate hain — jab tak user
  // khud "Apply" na dabaye, humara custom filter kabhi apply hi nahi hota.
  // Isliye yahan turant, restored/default drState ke saath charts ko
  // humare apne API se render karte hain — taaki refresh ke baad bhi
  // sahi (saved) date-range ka data dikhe, na ki galat default month ka.
  var initialPayload = {
    from: drState.from,
    to: drState.to,
    view: drState.view,
    company: drState.company
  };

  // Chart widgets DOM mein render hone mein thoda time lete hain.
  // ✅ Pehle 2 blind setTimeout the (1200ms + 2500ms) jisse har baar
  // script re-run hone par (jaise report se wapas dashboard pe aane par)
  // 2 baar refresh dikhta tha. Ab widgets ready hone ka poll karte hain
  // aur EK hi baar apply karte hain — jab tak apply ho na jaaye ya
  // max attempts khatam na ho jaayein.
  var readyCheckAttempts = 0;
  var maxReadyCheckAttempts = 15; // ~7.5 second tak try karega (500ms interval)
  var readyCheckInterval = setInterval(function() {
    readyCheckAttempts++;
    var widgetsPresent = document.querySelectorAll('.dashboard-widget-box .chart-container').length > 0;

    if (widgetsPresent || readyCheckAttempts >= maxReadyCheckAttempts) {
      clearInterval(readyCheckInterval);
      applyDashboardFilters(initialPayload); // sirf EK baar
    }
  }, 500);
})();

/* ────────────────────────────────────────────────────────────────
   ✅ WORKAROUND #1 — Native funnel/filter icon ko poori tarah
   disable karo. Ye buggy native filter-dialog machinery ko kabhi
   trigger hi nahi hone deta — isliye hang bhi kabhi nahi hoga,
   chahe uska asli root-cause kuch bhi ho. User sirf humare apne
   already-working date-range widget se hi filter karega.
   ──────────────────────────────────────────────────────────────── */
function disableNativeChartFunnelIcons() {
  document.querySelectorAll('.dashboard-widget-box').forEach(function(el) {
    // Frappe alag-alag versions mein alag selector use karta hai,
    // isliye SVG icon ke "href" mein "filter" text dhoondte hain —
    // ye generic hai, kisi bhi version mein match kar jayega.
    el.querySelectorAll('svg use').forEach(function(useEl) {
      var href = useEl.getAttribute('href') || useEl.getAttribute('xlink:href') || '';
      if (href.indexOf('filter') === -1) return;

      var btn = useEl.closest('button, a, .btn');
      if (!btn || btn.dataset.drFunnelDisabled) return;

      btn.dataset.drFunnelDisabled = '1';
      btn.style.display = 'none';   // icon hi hide kar do, click hi nahi hoga
    });
  });
}

// Page load ke thodi der baad apply karo (widgets render hone ka wait)
setTimeout(disableNativeChartFunnelIcons, 1500);
setTimeout(disableNativeChartFunnelIcons, 3000);

// Har baar date-range apply/re-render hone ke baad bhi dobara apply karo,
// kyunki chart card re-render hone par icon wapas aa sakta hai
var _origFetchAndRenderChart = fetchAndRenderChart;
fetchAndRenderChart = function(chartName, payload, cb) {
  _origFetchAndRenderChart(chartName, payload, function(ok) {
    setTimeout(disableNativeChartFunnelIcons, 300);
    if (cb) cb(ok);
  });
};

/* ────────────────────────────────────────────────────────────────
   ✅ WORKAROUND #2 — "..." menu ke "action-list" (jo actual me
   "Sales Invoice List" / "Sales Progress Report" / etc. text ke
   saath render hota hai — text alag-alag hota hai per chart, isliye
   text-match kaam nahi karta) click ko intercept karke, current LIVE
   filter state (drState) se sahi report (chartName ke naam se) khud
   khol dete hain — na ki jo bhi native link uska target hai.

   ⚠️ CONFIRMED via console: actual markup hamesha ye hota hai:
     <a class="dropdown-item" data-action="action-list">...</a>
   Isliye ab hum text ki jagah data-action="action-list" attribute
   se match karte hain — reliable, version-independent.

   ✅ GUARD: agar ye script kisi wajah se dobara execute ho (SPA
   remount), purana listener replace karte hain (naya add karne se
   pehle purana hata dete hain) — taaki kabhi 2 listeners ek saath na
   ho jaayein jo ek-doosre ko silently block kar sakte hain.
   ──────────────────────────────────────────────────────────────── */
if (window._drActionListClickHandler) {
  document.removeEventListener('click', window._drActionListClickHandler, true);
}

window._drActionListClickHandler = function(e) {
  var target = e.target.closest('a[data-action="action-list"]');
  if (!target) return;

  // ✅ Unconditional log — isse pata chalega ki listener bilkul fire
  // ho raha hai ya nahi, chahe aage match fail ho ya succeed
  console.log('DR DEBUG: action-list link clicked (listener fired)');

  var widgetEl = target.closest('.dashboard-widget-box');
  if (!widgetEl) {
    console.log('DR DEBUG: action-list clicked but no widget context found');
    return;
  }

  var rawTitle = widgetEl.querySelector('.ellipsis')?.textContent?.trim() || '';

  // ✅ Exact match pehle try karo, fir case-insensitive/trimmed fallback
  // (taaki extra space ya case-difference ki wajah se match fail na ho)
  var chartName = null;
  if (CHART_FILTER_MAP[rawTitle]) {
    chartName = rawTitle;
  } else {
    var normalizedRaw = rawTitle.replace(/\s+/g, ' ').trim().toLowerCase();
    chartName = Object.keys(CHART_FILTER_MAP).find(function(key) {
      return key.replace(/\s+/g, ' ').trim().toLowerCase() === normalizedRaw;
    });
  }

  if (!chartName) {
    console.log('DR DEBUG: action-list clicked, widget found but chartName unmapped. Raw title was:', JSON.stringify(rawTitle));
    console.log('DR DEBUG: known chart names are:', Object.keys(CHART_FILTER_MAP));
    return; // native path chalega (isliye "Sales Invoice List" jaisa dikh sakta hai)
  }

  // Native click ko poori tarah roko (jo shayad kisi doosre/galat
  // report ya list-view pe le jaata), hum khud sahi report khud kholenge
  e.preventDefault();
  e.stopPropagation();
  if (e.stopImmediatePropagation) e.stopImmediatePropagation();

  var currentPayload = {
    from: drState.from,
    to: drState.to,
    view: drState.view,
    company: drState.company
  };

  console.log('DR DEBUG: action-list intercepted for', chartName, 'with payload', currentPayload);

  var reportFilters = buildReportFilters(chartName, currentPayload);
  var actualReportName = REPORT_NAME_MAP[chartName] || chartName;
  frappe.set_route('query-report', actualReportName, reportFilters);
};

document.addEventListener('click', window._drActionListClickHandler, true); // capture phase — native handler se pehle hi intercept karo

style:
/* ── Wrapper ───────────────────────────────────────────────── */
.dr-container {
  font-family: 'Segoe UI', sans-serif;
  padding: 6px 0;
}

.dr-bar {
  display: flex;
  align-items: center;
  width: 100%;
}

/* ── Date Range Button ─────────────────────────────────────── */
.dr-section {
  position: relative;
  flex: 0 0 auto;
}

.dr-main-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  background: #fff;
  border: 1px solid #d0d5dd;
  border-radius: 6px;
  font-size: 13px;
  color: #333;
  cursor: pointer;
  white-space: nowrap;
  transition: border-color 0.15s, background 0.15s;
}
.dr-main-btn:hover {
  border-color: #1D9E75;
  background: #f6fdf9;
}

.dr-chevron {
  font-size: 9px;
  color: #999;
  margin-left: 2px;
  transition: transform 0.2s;
  display: inline-block;
}
.dr-chevron.open {
  transform: rotate(180deg);
}

/* ── Dropdown Panel ────────────────────────────────────────── */
.dr-dropdown {
  display: none;
  position: absolute;
  top: calc(100% + 5px);
  left: 0;
  min-width: 210px;
  background: #fff;
  border: 1px solid #ddd;
  border-radius: 8px;
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.13);
  z-index: 9999;
  overflow: visible;
}
.dr-dropdown.open {
  display: block;
}

/* ── Preset Options ────────────────────────────────────────── */
.dr-option {
  padding: 9px 18px;
  font-size: 13px;
  color: #333;
  cursor: pointer;
  border-bottom: 1px solid #f2f2f2;
  transition: background 0.1s;
}
.dr-option:last-of-type {
  border-bottom: none;
}
.dr-option:hover {
  background: #f5f5f5;
}
.dr-option.dr-active {
  background: #1D9E75;
  color: #fff;
  font-weight: 600;
}

/* ── Custom Date Inputs ────────────────────────────────────── */
.dr-custom-box {
  display: none;
  padding: 10px 16px;
  background: #f9f9f9;
  border-top: 1px solid #eee;
  border-bottom: 1px solid #eee;
  position: relative;
  z-index: 10000;
}

.dr-date-row input[type="date"] {
  flex: 1;
  padding: 5px 8px;
  border: 1px solid #ccc;
  border-radius: 5px;
  font-size: 12px;
  color: #333;
  background: #fff;
  outline: none;
  position: relative;
  z-index: 10001;
  pointer-events: all;
}
.dr-custom-box.open {
  display: block;
}

.dr-date-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}
.dr-date-row:last-child {
  margin-bottom: 0;
}
.dr-date-row label {
  font-size: 12px;
  color: #666;
  min-width: 30px;
}
.dr-date-row input[type="text"] {
  flex: 1;
  padding: 5px 8px;
  border: 1px solid #ccc;
  border-radius: 5px;
  font-size: 12px;
  color: #333;
  background: #fff;
  outline: none;
}
.dr-date-row input[type="text"]:focus {
  border-color: #1D9E75;
}

/* ── Apply / Cancel inside dropdown ───────────────────────── */
.dr-dropdown-actions {
  display: flex;
  gap: 8px;
  padding: 10px 16px;
  background: #fff;
  border-top: 1px solid #f0f0f0;
}

.dr-apply-btn {
  flex: 1;
  padding: 7px 0;
  background: #1D9E75;
  color: #fff;
  border: none;
  border-radius: 5px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
